VALUES
  ('aboriginal-c5fb3965-moex-00018', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民族健康法，中央教育主管機關應鼓勵各健康照護相關科系之大專校院課程內容，融入原住 民族健康事務相關課程之教學或學習活動，以學習如何以原住民族知識體系為主，確保原住民族於健 康照護領域中獲得公平、適當之健康服務，使其身分或文化得到適足保障。此一課程稱之為下列何種 課程？', '["健康平等課程", "文化安全課程", "文化敏感度課程", "多元文化課程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00019', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '為讓各級各類學校實施原住民族語言、文化及藝能教學，遴聘原住民族耆老或具相關專長人士支援教 學，特制定下列何項法規？', '["原住民族語言推廣人員設置辦法", "高級中等以下學校原住民族語老師資格及聘用辦法", "原住民族文化及藝能認證辦法", "原住民族文化從業人員進修學分獎勵要點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00020', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '有關原住民族地區，下列敘述何者錯誤？', '["原住民族地區之分類乃係依行政區劃分", "原住民族地區可分為山地及平地原住民鄉（鎮、市）", "新北市烏來區屬山地原住民鄉", "嘉義縣阿里山鄉屬平地原住民鄉"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00021', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民地區參與再生能源設置示範獎勵辦法規定，原住民族地區之再生能源發電設備及儲能設備，中 央主管機關得基於示範之目的，於一定期間內，給予相關獎勵。請問下列何者不是該辦法所定的措施？', '["獎勵對象為原住民族地區之鄉鎮市區公所", "分兩階段獎勵", "得視狀況免除或簡化程序，如原住民族基本法所規定諮商取得原住民族或部落同意之程序", "規劃評估獎勵額度以新臺幣二百萬元為上限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00022', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民保留地禁伐補償條例於今（113）年修正，將禁伐補償金提高至每年每公頃新臺幣6萬元，並 增加定期檢討機制，請問中央主管機關應依何種經濟數據檢討補償金額度？', '["國民生產毛額", "消費者物價指數", "原住民家戶平均收入", "森林產物市價中位數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00023', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '針對原住民族健康法之規定，下列描述何者錯誤？', '["中央主管機關應設置專責單位辦理原住民族健康事務", "原住民族健康政策，應尊重原住民族意願及自主發展之精神", "為落實及推動原住民族健康政策，中央主管機關應遴聘（派）原住民族代表、有關機關代表及原住 民族健康照護專家學者，召開原住民族健康政策會", "本法所定事項，涉及各中央目的事業主管機關職掌者，各該主管機關應配合辦理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00024', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據高級中等以下學校原住民族語老師資格及聘用辦法規定，原住民族語老師應取得原住民族委員會 核發之原住民族語言能力認證考試合格證書或原住民族語言能力認證測驗高級以上合格證書之外，須 符合特定資格始得擔任。請問下列何者為非上開辦法所定資格：', '["取得原住民族委員會核發之原住民族語言能力認證合格人員研習結業證書", "取得大學校院依原住民族語言師資培育計畫辦理核發之修畢學分證明書", "取得直轄市、縣（市）政府核發之教學支援人員研習合格證書", "原住民年滿55歲，精熟族語，並取得原住民族部落或相關機關、原住民族部落團體之舉薦證書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00025', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '為保障原住民得以合理條件申請取得有關社會福利措施，在計算原住民個人或家庭財產時，依據社會 救助法規定，應如何計算原住民保留地之財產價值？', '["應以當地實價登錄之七成計算其財產價值", "認定為未產生經濟效益之土地者，應扣除計算土地價值", "應以所能取得禁伐補償價金為其財產價值", "應以國有原住民保留地出租衍生收益計算其財產價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00026', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依大專校院健康照護相關科系融入原住民族健康事務文化安全課程實施辦法第3條之規定，大專校院 規劃相關課程得參照融入之事項，下列何者不屬之？', '["原住民族權利促進運動", "原住民族社會與健康不均等", "原住民族文化復振與社會安全", "文化敏感度之照顧議題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00027', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民族工作權保障法第12條及第24條規定（以下稱系爭規定），經司法院大法官會議以釋字第719 號及釋字第810號作成解釋。針對大法官的兩號解釋，下列描述何者錯誤？', '["系爭規定可能造成個案顯然過苛之情狀，致有嚴重侵害人民財產權之不當後果，於此範圍內，顯不 符相當性而有違憲法第23條比例原則，有關機關應至遲於本解釋公布之日起2年內依本解釋意旨 修正之；逾期未完成者，系爭規定失其效力", "系爭規定要求特定得標廠商，於履約期間須進用一定比例之原住民，係對其是否增僱或選擇受僱對 象等營業自由形成一定限制。而得標廠商未達進用原住民之標準者須繳納代金，則屬對其財產權之 侵害", "立法者為促進原住民就業、改善其經濟與社會狀況，而制定系爭規定，符合國際保障原住民族之精 神。是系爭規定係為維護重要之公共利益，目的洵屬正當", "系爭規定所能提供之工作機會多屬短期或不具技術性之工作，難以增進原住民長期穩定之工作機會 及專業技能，國家仍應定期檢討修正。又得標廠商未僱用一定比例之原住民而須繳納代金，其金額 如超過政府採購金額者，允宜有適當之減輕機制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
